def remove_Occ(s: str, char: str) -> str:
    """
    Remove the first and last occurrence of a given character from the string.

    Args:
        s (str): The input string.
        char (str): The character to remove.

    Returns:
        str: The modified string with the first and last occurrences of the character removed.
    """
    if not char:
        return s

    first_index = s.find(char)
    if first_index == -1:
        return s

    last_index = s.rfind(char)
    if last_index == -1:
        return s

    # If first and last are the same, remove only that one occurrence
    if first_index == last_index:
        return s[:first_index] + s[first_index+1:]

    # If first and last are different, remove both
    if first_index == 0 and last_index == len(s) - 1:
        return s[1:-1]
    elif first_index == 0:
        return s[1:last_index]
    elif last_index == len(s) - 1:
        return s[:first_index] + s[last_index:]
    else:
        return s[:first_index] + s[first_index+1:last_index] + s[last_index+1:]

