def text_lowercase_underscore(s):
    if not s:
        return False

    # Check if the string contains only lowercase letters and underscores
    if not all(c.islower() or c == '_' for c in s):
        return False

    # Check if underscores are only used as separators between lowercase letters
    # and that there are no consecutive underscores or underscores at start/end
    if s.startswith('_') or s.endswith('_'):
        return False

    if '__' in s:
        return False

    # Ensure that underscores are surrounded by lowercase letters
    parts = s.split('_')
    if any(not part or not part.isalpha() for part in parts):
        return False

    return True

