def text_lowercase_underscore(text):
    if not text:
        return False
    # The pattern ensures:
    # 1. The string consists only of lowercase letters and underscores.
    # 2. Underscores only appear between lowercase letters (no leading/trailing underscores, no consecutive underscores).
    pattern = r'^[a-z]+(_[a-z]+)*$'
    return bool(re.match(pattern, text))

