def comb_sort(arr):
    n = len(arr)
    if n <= 1:
        return arr

    gap = n
    swapped = True

    while gap > 1 or swapped:
        # Update gap value
        gap = (gap // 13) + 1
        if gap > 1:
            swapped = False

        # Traverse the array with current gap
        for i in range(n - gap):
            if arr[i] > arr[i + gap]:
                # Swap elements
                arr[i], arr[i + gap] = arr[i + gap], arr[i]
                swapped = True

    return arr

