def is_samepatterns(patterns: list, sequences: list) -> bool:
    """
    Check if the sequences follow the same pattern as the patterns list.

    Args:
        patterns: A list of unique pattern strings (e.g., ["a", "b", "b"]).
        sequences: A list of strings to check against the pattern.

    Returns:
        True if sequences follow the pattern, False otherwise.
    """
    if len(patterns) != len(sequences):
        return False

    pattern_to_char = {}
    char_to_pattern = {}

    for pattern_char, seq_char in zip(patterns, sequences):
        if pattern_char not in pattern_to_char:
            if seq_char in char_to_pattern:
                return False
            pattern_to_char[pattern_char] = seq_char
            char_to_pattern[seq_char] = pattern_char
        elif pattern_to_char[pattern_char] != seq_char:
            return False

    return True

def is_samepatterns(patterns, patterns_map):
    """
    Check if the strings in 'patterns' follow the same grouping sequence as 'patterns_map'.

    This means that if patterns_map[i] == patterns_map[j], then patterns[i] must equal patterns[j],
    and vice versa. It checks for a consistent one-to-one mapping between indices in patterns_map
    and the corresponding strings in patterns.

    Args:
        patterns (List[str]): The list of strings to check.
        patterns_map (List[str]): The list of pattern characters/strings representing the expected sequence.

    Returns:
        bool: True if the patterns follow the same sequence as patterns_map, False otherwise.
    """
    if len(patterns) != len(patterns_map):
        return False

    # Dictionary to store the first occurrence index of each pattern character
    pattern_to_index = {}
    # Dictionary to store the first occurrence index of each string in patterns
    string_to_index = {}

    for i in range(len(patterns)):
        char = patterns_map[i]
        word = patterns[i]

        if char in pattern_to_index:
            if pattern_to_index[char] != string_to_index.get(word, -1):
                return False
        else:
            pattern_to_index[char] = i
            string_to_index[word] = i

    # Ensure that each unique character in patterns_map maps to exactly one unique string in patterns
