def is_undulating(n: int) -> bool:
    """
    Check if the given integer is an undulating number.

    An undulating number is a number whose adjacent digits are never equal
    and alternate between increasing and decreasing.

    Examples:
        1212121 -> True (alternates: <, >, <, >, <, >)
        123121 -> False (breaks alternation at 2->3->1)
        122121 -> False (adjacent equal digits)
    """
    s = str(n)
    if len(s) <= 1:
        return False

    # Check for any adjacent equal digits
    for i in range(len(s) - 1):
        if s[i] == s[i+1]:
            return False

    # Check alternation of increasing/decreasing
    prev_direction = None  # None means no direction yet
    for i in range(len(s) - 1):
        curr = s[i+1]
        prev = s[i]

        if curr > prev:
            direction = 'up'
        elif curr < prev:
            direction = 'down'
        else:
            return False  # Already checked for equality, but for safety

        if prev_direction is None:
            prev_direction = direction
        elif prev_direction != direction:
            continue  # Alternation is correct
        else:
            return False  # Direction did not alternate

    return True

