def next_smallest_palindrome(n: int) -> int:
    """
    Returns the smallest palindrome strictly greater than n.
    """
    n = int(n)
    if n < 0:
        return -999  # or handle negative case as needed; example only covers positive
    if n >= 0:
        def make_palindrome(left: str) -> int:
            length = len(left)
            if length % 2 == 1:
                right = left[:-1][::-1]
            else:
                right = left[::-1]
            return int(left + right)

        def next_palindrome_after(n: int) -> int:
            s = str(n)
            length = len(s)

            # Try to form a palindrome by mirroring the left half
            left = s[: (length + 1) // 2]
            candidate = make_palindrome(left)

            if candidate > n:
                return candidate

            # If the mirrored palindrome is <= n, increment the left half
            # and form a new palindrome
            left += 1
            return make_palindrome(left)

        return next_palindrome_after(n)
    else:
        raise ValueError("Input must be non-negative.")

