    """
    Finds the element that appears only once in a sorted array.

    The array is guaranteed to have exactly one unique element.
    """
    n = len(arr)
    if n == 1:
        return arr[0]

    # Use binary search since the array is sorted
    left, right = 0, n - 1

    while left < right:
        mid = (left + right) // 2

        # Check if mid is the unique element
        if mid == 0:
            if arr[mid] == arr[mid + 1]:
                left = mid + 1
            else:
                return arr[mid]
        elif mid == n - 1:
            if arr[mid] == arr[mid - 1]:
                right = mid - 1
            else:
                return arr[mid]
        else:
            # If the element at mid is the same as the next one,
            # the unique element must be to the right
            if arr[mid] == arr[mid + 1]:
                left = mid + 1
            # If the element at mid is the same as the previous one,
            # the unique element must be to the left
            elif arr[mid] == arr[mid - 1]:
                right = mid - 1
            else:
                return arr[mid]

    return arr[left]

