def amicable_numbers_sum(n):
    def sum_divisors(num):
        if num < 2:
            return num
        total = 1
        for i in range(2, int(num ** 0.5) + 1):
            if num % i == 0:
                total += i
                if i != num // i and num // i != num:
                    total += num // i
        return total

    amicable_pairs = set()
    for i in range(1, n + 1):
        j = sum_divisors(i)
        if i != j and sum_divisors(j) == i and j <= n:
            amicable_pairs.add(min(i, j))
            amicable_pairs.add(max(i, j))

    return sum(amicable_pairs)

