def is_majority(arr, n, element):
    if n == 0:
        return False

    # Find the first occurrence of the element
    left = 0
    right = n - 1
    first_occurrence = -1

    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == element:
            first_occurrence = mid
            right = mid - 1
        elif arr[mid] < element:
            left = mid + 1
        else:
            right = mid - 1

    if first_occurrence == -1:
        return False

    # Find the last occurrence of the element
    left = 0
    right = n - 1
    last_occurrence = -1

    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == element:
            last_occurrence = mid
            left = mid + 1
        elif arr[mid] < element:
            left = mid + 1
        else:
            right = mid - 1

    # Count occurrences
    count = last_occurrence - first_occurrence + 1

    return count > n // 2

