    right = n // 2

    while left >= 0 and arr[left] == element:
        left -= 1
    while right < n and arr[right] == element:
        right += 1

    count = right - left - 1
    return count > n // 2

def is_majority(arr, n, element):
    if n == 0:
        return False

    # Since the array is sorted, we can use binary search to find the first and last occurrence
    # of the element. If the count of the element is more than n/2, it's a majority element.

    # Find the first occurrence of the element
    left = 0
    right = n - 1
    first_occurrence = -1

    while left <= right:
        mid = (left + right) // 2
        if arr[mid] >= element:
            right = mid - 1
        else:
            left = mid + 1

    # Adjust left to the first occurrence if arr[left] == element
    if left < n and arr[left] == element:
        first_occurrence = left
    else:
        return False  # Element not found

    # Find the last occurrence of the element
    left = 0
    right = n - 1
    last_occurrence = -1

    while left <= right:
        mid = (left + right) // 2
        if arr[mid] <= element:
            left = mid + 1
        else:
            right = mid - 1

    # Adjust right to the last occurrence if arr[right] == element
    if right >= 0 and arr[right] == element:
        last_occurrence = right
    else:
        return False  # Element not found

    # Calculate the count of the element
    count = last_occurrence - first_occurrence + 1

    # Check if the count is more than n/2
    return count > n // 2

def is_majority(arr, n, element):
    if n == 0:
        return False

    # Since the array is sorted, the element must be in the middle half to be a majority
    # If it's a majority, it must appear more than n/2 times.
    # In a sorted array, if an element appears more than n/2 times,
    # it must occupy the middle position (index n//2).

    if arr[n // 2] != element:
        return False

    # Count occurrences of the element
    left = 0
    right = n - 1

    # Find first occurrence
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == element:
            if mid > 0 and arr[mid - 1] == element:
                left = mid + 1
            else:
                break
        elif arr[mid] < element:
            left = mid + 1
        else:
            right = mid - 1

    # Find last occurrence
    left = 0
    right = n - 1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == element:
            if mid < n - 1 and arr[mid + 1] == element:
                right = mid - 1
            else:
                break
        elif arr[mid] < element:
            left = mid + 1
        else:
            right = mid - 1

    count = right - left + 1
    return count > n // 2
